  ('40000000-0000-4000-8000-000000000002', 'CA FTB Newsroom', 'https://www.ftb.ca.gov/about-ftb/newsroom/index.html', CAST(unixepoch('2026-05-17 07:30:00') * 1000 AS INTEGER), 'deadline_shift', 'due_date_overlay', 'FTB extends the LLC payment deadline to May 30, 2026 for San Diego County taxpayers.', 'The Franchise Tax Board extends the LLC payment deadline to May 30, 2026 for San Diego County taxpayers.', 'CA', '["San Diego"]', '["ca_llc_568"]', '["llc"]', CAST(unixepoch('2026-04-30 00:00:00') * 1000 AS INTEGER), CAST(unixepoch('2026-05-30 00:00:00') * 1000 AS INTEGER), CAST(unixepoch('2026-04-30 00:00:00') * 1000 AS INTEGER), NULL, 0.82, 'approved', 'mock_user_owner_sarah', CAST(unixepoch('2026-05-17 08:30:00') * 1000 AS INTEGER), 1, 1, CAST(unixepoch('2026-05-17 07:35:00') * 1000 AS INTEGER), CAST(unixepoch('2026-05-17 08:30:00') * 1000 AS INTEGER)),
  ('40000000-0000-4000-8000-000000000003', 'NY DTF', 'https://www.tax.ny.gov/bus/ptet/', CAST(unixepoch('2026-05-16 16:00:00') * 1000 AS INTEGER), 'form_instruction', 'review_only', 'NY DTF clarifies the pass-through entity tax (PTET) election window. Low-confidence advisory — review applicability for your partnerships.', 'The PTET election for tax year 2026 must be made by March 15, 2026.', 'NY', '[]', '["ny_it204"]', '["partnership"]', NULL, NULL, NULL, '{"note":"PTET election reminder only."}', 0.58, 'approved', 'mock_user_owner_sarah', CAST(unixepoch('2026-05-16 16:30:00') * 1000 AS INTEGER), 1, 1, CAST(unixepoch('2026-05-16 16:05:00') * 1000 AS INTEGER), CAST(unixepoch('2026-05-16 16:30:00') * 1000 AS INTEGER)),
  ('40000000-0000-4000-8000-000000000004', 'FL DOR', 'https://floridarevenue.com/taxes/taxesfees/Pages/corporate.aspx', CAST(unixepoch('2026-05-15 17:00:00') * 1000 AS INTEGER), 'applicability_scope', 'review_only', 'FL DOR corporate income-tax bulletin. Very-low-confidence extraction — applicability depends on entity status, fiscal year, and extension election.', 'Corporate income tax filing dates may depend on entity status, fiscal year, and extension election.', 'FL', '[]', '["fl_corp_income"]', '["c_corp"]', NULL, NULL, NULL, '{"note":"Applicability depends on fiscal year and extension election."}', 0.46, 'approved', 'mock_user_owner_sarah', CAST(unixepoch('2026-05-15 17:30:00') * 1000 AS INTEGER), 1, 1, CAST(unixepoch('2026-05-15 17:05:00') * 1000 AS INTEGER), CAST(unixepoch('2026-05-15 17:30:00') * 1000 AS INTEGER)),
  ('40000000-0000-4000-8000-000000000008', 'IRS Bulletin', 'https://www.irs.gov/forms-pubs/about-schedule-k-3-form-1065', CAST(unixepoch('2026-05-01 06:40:00') * 1000 AS INTEGER), 'filing_requirement', 'review_only', 'IRS requires Schedule K-3 attachment for all partnership 1065 filings effective tax year 2026.', 'All partnerships that file Form 1065 must now attach Schedule K-3 reporting items of international tax relevance, regardless of partner residency.', 'FED', '[]', '["federal_1065"]', '["llc","partnership"]', NULL, NULL, CAST(unixepoch('2026-01-01 00:00:00') * 1000 AS INTEGER), NULL, 0.92, 'approved', 'mock_user_owner_sarah', CAST(unixepoch('2026-05-01 07:10:00') * 1000 AS INTEGER), 1, 1, CAST(unixepoch('2026-05-01 06:45:00') * 1000 AS INTEGER), CAST(unixepoch('2026-05-01 07:10:00') * 1000 AS INTEGER)),
  ('40000000-0000-4000-8000-000000000009', 'NY DTF Newsroom', 'https://www.tax.ny.gov/about/press/mta-scope-2026.htm', CAST(unixepoch('2026-04-27 11:00:00') * 1000 AS INTEGER), 'applicability_scope', 'review_only', 'NY MTA surcharge scope expanded to Brooklyn and Queens for tax year 2026 (was Manhattan + Bronx only).', 'The Metropolitan Transportation Business Tax Surcharge now applies to qualifying business activity sourced to Brooklyn (Kings County) and Queens in addition to the previously covered counties.', 'NY', '["Brooklyn","Queens"]', '["ny_mta_surcharge"]', '["llc","partnership","c_corp"]', NULL, NULL, CAST(unixepoch('2026-01-01 00:00:00') * 1000 AS INTEGER), NULL, 0.88, 'approved', 'mock_user_owner_sarah', CAST(unixepoch('2026-04-27 13:00:00') * 1000 AS INTEGER), 1, 1, CAST(unixepoch('2026-04-27 11:15:00') * 1000 AS INTEGER), CAST(unixepoch('2026-04-27 13:00:00') * 1000 AS INTEGER)),
  ('40000000-0000-4000-8000-000000000010', 'IRS Newsroom', 'https://www.irs.gov/instructions/i1120sk3', CAST(unixepoch('2026-04-25 09:00:00') * 1000 AS INTEGER), 'form_instruction', 'review_only', 'IRS clarifies 1120-S Schedule K-3 instructions for foreign-sourced shareholder income reporting.', 'S corporations with shareholders receiving foreign-source income should report on Schedule K-3 Part X, lines 11 through 18, regardless of whether the corporation has international operations.', 'FED', '[]', '["federal_1120s"]', '["s_corp"]', NULL, NULL, CAST(unixepoch('2026-04-25 00:00:00') * 1000 AS INTEGER), NULL, 0.74, 'approved', 'mock_user_owner_sarah', CAST(unixepoch('2026-04-25 11:00:00') * 1000 AS INTEGER), 1, 1, CAST(unixepoch('2026-04-25 09:15:00') * 1000 AS INTEGER), CAST(unixepoch('2026-04-25 11:00:00') * 1000 AS INTEGER)),
  ('40000000-0000-4000-8000-000000000011', 'TX Comptroller', 'https://comptroller.texas.gov/taxes/franchise/', CAST(unixepoch('2026-05-01 09:20:00') * 1000 AS INTEGER), 'source_status', 'review_only', 'TX Comptroller RSS feed degraded — last successful poll 24h ago. No content gap detected, but watch this row for follow-ups.', 'Source health status: degraded. Last successful poll completed 24 hours ago; manual verification recommended for upcoming TX franchise report cycles.', 'TX', '[]', '["tx_franchise_report"]', '["llc","c_corp"]', NULL, NULL, CAST(unixepoch('2026-05-01 00:00:00') * 1000 AS INTEGER), NULL, 0.95, 'approved', 'mock_user_owner_sarah', CAST(unixepoch('2026-05-01 09:30:00') * 1000 AS INTEGER), 1, 1, CAST(unixepoch('2026-05-01 09:25:00') * 1000 AS INTEGER), CAST(unixepoch('2026-05-01 09:30:00') * 1000 AS INTEGER)),
  ('40000000-0000-4000-8000-000000000012', 'WA Department of Revenue', 'https://dor.wa.gov/taxes-rates/business-occupation-tax/special-tax-rates', CAST(unixepoch('2026-04-22 14:00:00') * 1000 AS INTEGER), 'new_obligation', 'review_only', 'WA introduces new gross receipts surtax for tech firms — first filings due Sept 30 2026.', 'Effective July 1 2026, businesses primarily engaged in software publishing, computer system design, or data hosting with WA-sourced gross receipts above $25M will be subject to a new 1.22% surtax. First quarterly returns are due September 30 2026.', 'WA', '[]', '["wa_tech_surtax_q3"]', '["c_corp","llc"]', NULL, CAST(unixepoch('2026-09-30 00:00:00') * 1000 AS INTEGER), CAST(unixepoch('2026-07-01 00:00:00') * 1000 AS INTEGER), NULL, 0.91, 'approved', 'mock_user_owner_sarah', CAST(unixepoch('2026-04-22 15:30:00') * 1000 AS INTEGER), 1, 1, CAST(unixepoch('2026-04-22 14:15:00') * 1000 AS INTEGER), CAST(unixepoch('2026-04-22 15:30:00') * 1000 AS INTEGER)),
