  ('40000000-0000-4000-8000-000000000014', 'IRS', 'https://www.irs.gov/newsroom/irs-releases-tax-inflation-adjustments-for-tax-year-2026', CAST(unixepoch('2026-05-15 14:00:00') * 1000 AS INTEGER), 'threshold_advisory', 'review_only', 'IRS released the annual inflation-adjustment Revenue Procedure. Review thresholds (gift/estate exclusions, estimated-tax safe harbor) — open the official source for the adjusted figures.', 'See the official IRS Revenue Procedure for the adjusted figures.', 'FED', '[]', '[]', '[]', NULL, NULL, NULL, '{"kind":"threshold_advisory","sourceId":"fed.irs_inflation_adjustments_2026","sourceUrl":"https://www.irs.gov/newsroom/irs-releases-tax-inflation-adjustments-for-tax-year-2026"}', 1, 'approved', 'mock_user_owner_sarah', CAST(unixepoch('2026-05-14 14:30:00') * 1000 AS INTEGER), 0, 1, CAST(unixepoch('2026-05-14 14:05:00') * 1000 AS INTEGER), CAST(unixepoch('2026-05-14 14:30:00') * 1000 AS INTEGER)),
