INSERT INTO rule_note
  (id, firm_id, rule_id, author_id, body, parent_note_id, created_at, updated_at)
VALUES
  ('6a000000-0000-4000-8000-000000000001', 'mock_firm_brightline', 'ca.individual_estimated_tax.candidate.2026', 'mock_user_partner_priya', 'Holding this one until we confirm the Q1 installment date against the FTB schedule. CA estimated tax is front-loaded (30/40/0/30), so the first voucher does most of the work — I want the concrete date pinned before any client reminders go out.', NULL, CAST(unixepoch('2026-06-02 10:15:00') * 1000 AS INTEGER), CAST(unixepoch('2026-06-02 10:15:00') * 1000 AS INTEGER)),
  ('6a000000-0000-4000-8000-000000000002', 'mock_firm_brightline', 'ca.individual_estimated_tax.candidate.2026', 'mock_user_owner_sarah', 'Pulled the FTB page — Q1 lands on the federal April date and rolls to the next business day on weekends, matching the fixed-date logic the candidate now carries. Thresholds and the no-tax safe harbor look right. Comfortable accepting once you have eyes on the installment split.', '6a000000-0000-4000-8000-000000000001', CAST(unixepoch('2026-06-02 14:40:00') * 1000 AS INTEGER), CAST(unixepoch('2026-06-02 14:40:00') * 1000 AS INTEGER)),
  ('6a000000-0000-4000-8000-000000000003', 'mock_firm_brightline', 'ca.individual_estimated_tax.candidate.2026', 'mock_user_manager_miguel', 'One caveat before we flip it on: a handful of our CA individuals are below the estimated-payment threshold and should be scoped out so we do not nudge clients who owe nothing. I will tag the applicability list this afternoon, then this is ready to accept.', NULL, CAST(unixepoch('2026-06-03 09:05:00') * 1000 AS INTEGER), CAST(unixepoch('2026-06-03 09:05:00') * 1000 AS INTEGER));
